let lastTime = 0;
function gameLoop(timestamp) {
    let deltaTime = timestamp - lastTime;
    lastTime = timestamp;

    update(deltaTime);
    render();

    requestAnimationFrame(gameLoop);
}

在 update 函数中，根据游戏状态更新逻辑。

在 render 函数中，根据游戏状态绘制。

