首先，设置输入处理：
document.addEventListener('keydown', (e) => {
    handleInput(e.key, true);
});
document.addEventListener('keyup', (e) => {
    handleInput(e.key, false);
});

在 handleInput 中：
function handleInput(key, pressed) {
    keys[key] = pressed;
    if (key === ' ' && pressed && gameState === 'menu') {
        startGame();
    } else if (key === ' ' && pressed && gameState === 'playing') {
        shootBullet();
    } else if (key === 'p' && pressed) {
        togglePause();
    }
    // 移动在 update 中处理
}

在 update 中，处理玩家移动：
if (gameState === 'playing') {
    // 玩家移动
    player.dx = 0;
    if (keys['ArrowLeft'] || keys['a']) player.dx = -player.speed;
    if (keys['ArrowRight'] || keys['d']) player.dx = player.speed;
    player.x += player.dx;
    // 边界检查
    if (player.x < 0) player.x = 0;
    if (player.x + player.width > canvas.width) player.x = canvas.width - player.width;

    // 更新子弹
    bullets.forEach((bullet, index) => {
        bullet.y -= bullet.speed;
        if (bullet.y < 0) bullets.splice(index, 1);
    });

    // 更新敌机
    enemies.forEach((enemy, index) => {
        enemy.y += enemy.speed;
        // 如果敌机超出屏幕，移除并可能扣分或结束游戏？这里简单移除
        if (enemy.y > canvas.height) enemies.splice(index, 1);
    });

    // 生成敌机
    if (Math.random() < 0.02) { // 调整生成频率
        spawnEnemy();
    }

    // 碰撞检测
    checkCollisions();
}

定义 spawnEnemy：
function spawnEnemy() {
    let enemy = {
        x: Math.random() * (canvas.width - 30),
        y: -30,
        width: 30,
        height: 30,
        speed: 2 + Math.random() * 2
    };
    enemies.push(enemy);
}

shootBullet：
function shootBullet() {
    let bullet = {
        x: player.x + player.width / 2 - 2,
        y: player.y,
        width: 4,
        height: 10,
        speed: 7
    };
    bullets.push(bullet);
}

碰撞检测：
function checkCollisions() {
    // 子弹与敌机
    bullets.forEach((bullet, bIndex) => {
        enemies.forEach((enemy, eIndex) => {
            if (bullet.x < enemy.x + enemy.width &&
                bullet.x + bullet.width > enemy.x &&
                bullet.y < enemy.y + enemy.height &&
                bullet.y + bullet.height > enemy.y) {
                // 碰撞
                bullets.splice(bIndex, 1);
                enemies.splice(eIndex, 1);
                score += 10;
                // 更新最高分
                if (score > highScore) {
                    highScore = score;
                    localStorage.setItem('planeWarHighScore', highScore);
                }
            }
        });
    });

    // 敌机与玩家
    enemies.forEach((enemy, eIndex) => {
        if (player.x < enemy.x + enemy.width &&
            player.x + player.width > enemy.x &&
            player.y < enemy.y + enemy.height &&
            player.y + player.height > enemy.y) {
            // 游戏结束
            gameState = 'gameover';
        }
    });
}

在 render 中，绘制所有元素：
function render() {
    // 清空画布
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // 背景已经在 CSS 中设置，但为了覆盖，可以绘制一个矩形或直接使用 CSS 背景。既然 CSS 设置了背景，这里不需要额外绘制。

    if (gameState === 'menu') {
        drawMenu();
    } else if (gameState === 'playing') {
        drawGame();
    } else if (gameState === 'paused') {
        drawGame(); // 绘制游戏画面但半透明覆盖
        drawPauseScreen();
    } else if (gameState === 'gameover') {
        drawGame(); // 绘制游戏画面
        drawGameOverScreen();
    }
}

绘制函数：
function drawMenu() {
    ctx.fillStyle = 'white';
    ctx.font = '30px PingFang SC, Microsoft YaHei, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('飞机大战', canvas.width / 2, canvas.height / 2 - 50);
    ctx.font = '20px PingFang SC, Microsoft YaHei, sans-serif';
    ctx.fillText('按空格键开始游戏', canvas.width / 2, canvas.height / 2);
    ctx.fillText('最高分: ' + highScore, canvas.width / 2, canvas.height / 2 + 40);
}

function drawGame() {
    // 绘制玩家
    ctx.fillStyle = '#4fd1c5'; // 青色，与得分数值颜色一致
    ctx.fillRect(player.x, player.y, player.width, player.height);

    // 绘制敌机
    ctx.fillStyle = '#ff6b6b'; // 红色敌机
    enemies.forEach(enemy => {
        ctx.fillRect(enemy.x, enemy.y, enemy.width, enemy.height);
    });

    // 绘制子弹
    ctx.fillStyle = '#ffd93d'; // 黄色子弹
    bullets.forEach(bullet => {
        ctx.fillRect(bullet.x, bullet.y, bullet.width, bullet.height);
    });

    // 绘制得分
    ctx.fillStyle = 'white';
    ctx.font = '20px PingFang SC, Microsoft YaHei, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('得分: ', canvas.width / 2 - 30, 30);
    ctx.fillStyle = '#4fd1c5';
    ctx.fillText(score, canvas.width / 2 + 20, 30);
}

function drawPauseScreen() {
    ctx.fillStyle = 'rgba(0, 0, 0, 0.5)';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    ctx.fillStyle = 'white';
    ctx.font = '30px PingFang SC, Microsoft YaHei, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('游戏暂停', canvas.width / 2, canvas.height / 2);
    ctx.font = '20px PingFang SC, Microsoft YaHei, sans-serif';
    ctx.fillText('按 P 继续', canvas.width / 2, canvas.height / 2 + 40);
}

function drawGameOverScreen() {
    ctx.fillStyle = 'rgba(0, 0, 0, 0.5)';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    ctx.fillStyle = 'white';
    ctx.font = '30px PingFang SC, Microsoft YaHei, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('游戏结束', canvas.width / 2, canvas.height / 2 - 50);
    ctx.font = '20px PingFang SC, Microsoft YaHei, sans-serif';
    ctx.fillText('得分: ' + score, canvas.width / 2, canvas.height / 2);
    ctx.fillText('最高分: ' + highScore, canvas.width / 2, canvas.height / 2 + 40);
    ctx.fillText('按空格键重新开始', canvas.width / 2, canvas.height / 2 + 80);
}

startGame 函数：
function startGame() {
    gameState = 'playing';
    score = 0;
    player.x = canvas.width / 2;
    enemies = [];
    bullets = [];
}

togglePause：
function togglePause() {
    if (gameState === 'playing') {
        gameState = 'paused';
    } else if (gameState === 'paused') {
        gameState = 'playing';
    }
}

在 handleInput 中，当游戏结束时按空格键重新开始：
if (key === ' ' && pressed && gameState === 'gameover') {
    startGame();
}

现在，整合所有代码。

确保字体在绘制文本时使用：'PingFang SC, Microsoft YaHei, sans-serif'

在 CSS 中，设置 body 背景为深色，但 canvas 有背景，所以可能不需要。

